const input = $input.first().json;

const buyPrice = parseFloat(input.buy_price);
const sellPrice = parseFloat(input.sell_price);
const quantity = parseFloat(input.quantity) || 1;

const pnlAmount = Math.round((sellPrice - buyPrice) * quantity * 100) / 100;
const pnlPct = Math.round(((sellPrice - buyPrice) / buyPrice) * 10000) / 100;

let outcome = input.outcome;
if (!outcome) {
  if (pnlAmount > 0) outcome = 'WIN';
  else if (pnlAmount < 0) outcome = 'LOSS';
  else outcome = 'BREAKEVEN';
}

return [{
  json: {
    ticker: (input.ticker || '').toUpperCase().replace(/[^A-Z0-9.]/g, ''),
    buy_price: buyPrice,
    sell_price: sellPrice,
    quantity: quantity,
    pnl_amount: pnlAmount,
    pnl_pct: pnlPct,
    outcome: outcome,
    hit_take_profit: input.hit_tp || false,
    hit_stop_loss: input.hit_sl || false,
    exited_early: input.exited_early || false,
    feedback_tags: (() => { const raw = input.feedback_tags; if (!raw) return '[]'; if (typeof raw === 'string') { try { JSON.parse(raw); return raw; } catch(e) { return '[]'; } } return JSON.stringify(raw); })(),
    notes: input.notes || '',
    session_date: new Date().toISOString().split('T')[0],
  }
}];

const trade = $('Calculate P&L').first().json;
const pnlSign = trade.pnl_amount >= 0 ? '+' : '';

const response = `Trade logged successfully!

Ticker: ${trade.ticker}
Buy: $${trade.buy_price} | Sell: $${trade.sell_price}
Quantity: ${trade.quantity} shares
P&L: ${pnlSign}$${trade.pnl_amount} (${pnlSign}${trade.pnl_pct}%)
Outcome: ${trade.outcome}
${trade.feedback_tags && trade.feedback_tags !== '[]' ? 'Feedback: ' + trade.feedback_tags : ''}
${trade.notes ? 'Notes: ' + trade.notes : ''}`;

return [{ json: { response } }];
